import React, { useState, useEffect } from "react";
import { BrowserRouter as Router, Routes, Route, Navigate, Link, useNavigate } from "react-router-dom";
import axios from "axios";
import "./App.css";

// Axios defaults
axios.defaults.baseURL = "http://localhost:5001/api";

// Auth helper
const getAuthHeader = () => {
  const token = localStorage.getItem("token");
  return { headers: { Authorization: `Bearer ${token}` } };
};

// ✅ Login Page
function Login() {
  const [formData, setFormData] = useState({ email: "", password: "" });
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      const res = await axios.post("/login", formData);
      localStorage.setItem("token", res.data.token);
      localStorage.setItem("user", JSON.stringify(res.data.user));
      navigate("/dashboard");
    } catch (e) {
      alert("Invalid credentials");
    }
  };

  return (
    <div className="form-container">
      <h2>Login</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="email"
          placeholder="Email"
          value={formData.email}
          onChange={e => setFormData({ ...formData, email: e.target.value })}
          required
        />
        <div className="password-field">
          <input
            type={showPassword ? "text" : "password"}
            placeholder="Password"
            value={formData.password}
            onChange={e => setFormData({ ...formData, password: e.target.value })}
            required
          />
          <button type="button" onClick={() => setShowPassword(!showPassword)}>
            {showPassword ? "🙈" : "👁"}
          </button>
        </div>
        <button type="submit">Login</button>
        <p>Don’t have an account? <Link to="/register">Register</Link></p>
      </form>
    </div>
  );
}

// ✅ Register Page
function Register() {
  const [formData, setFormData] = useState({ name: "", email: "", password: "" });
  const [showPassword, setShowPassword] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async e => {
    e.preventDefault();
    try {
      await axios.post("/register", formData);
      alert("Registered successfully! Please login.");
      navigate("/login");
    } catch (e) {
      alert(e.response?.data?.message || "Error registering");
    }
  };

  return (
    <div className="form-container">
      <h2>Register</h2>
      <form onSubmit={handleSubmit}>
        <input
          type="text"
          placeholder="Name"
          value={formData.name}
          onChange={e => setFormData({ ...formData, name: e.target.value })}
          required
        />
        <input
          type="email"
          placeholder="Email"
          value={formData.email}
          onChange={e => setFormData({ ...formData, email: e.target.value })}
          required
        />
        <div className="password-field">
          <input
            type={showPassword ? "text" : "password"}
            placeholder="Password"
            value={formData.password}
            onChange={e => setFormData({ ...formData, password: e.target.value })}
            required
          />
          <button type="button" onClick={() => setShowPassword(!showPassword)}>
            {showPassword ? "🙈" : "👁"}
          </button>
        </div>
        <button type="submit">Register</button>
        <p>Already registered? <Link to="/login">Login</Link></p>
      </form>
    </div>
  );
}

// ✅ Dashboard
function Dashboard() {
  const [expenses, setExpenses] = useState([]);
  const [newExp, setNewExp] = useState({ description: "", amount: "" });

  const fetchExpenses = async () => {
    const res = await axios.get("/expense", getAuthHeader());
    setExpenses(res.data);
  };

  const addExpense = async e => {
    e.preventDefault();
    if (!newExp.description || !newExp.amount) return;
    await axios.post("/expense", newExp, getAuthHeader());
    setNewExp({ description: "", amount: "" });
    fetchExpenses();
  };

  const deleteExpense = async id => {
    await axios.delete(`/expense/${id}`, getAuthHeader());
    fetchExpenses();
  };

  useEffect(() => {
    fetchExpenses();
  }, []);

  return (
    <div className="dashboard">
      <h2>Dashboard</h2>
      <Link to="/profile">👤 Profile</Link>
      <form onSubmit={addExpense} className="expense-form">
        <input
          type="text"
          placeholder="Description"
          value={newExp.description}
          onChange={e => setNewExp({ ...newExp, description: e.target.value })}
        />
        <input
          type="number"
          placeholder="Amount"
          value={newExp.amount}
          onChange={e => setNewExp({ ...newExp, amount: e.target.value })}
        />
        <button type="submit">Add</button>
      </form>

      <ul>
        {expenses.map(e => (
          <li key={e._id}>
            {e.description} - ₹{e.amount}{" "}
            <button onClick={() => deleteExpense(e._id)}>❌</button>
          </li>
        ))}
      </ul>
    </div>
  );
}

// ✅ Profile
function Profile() {
  const [profile, setProfile] = useState({});
  const [editing, setEditing] = useState(false);
  const [newData, setNewData] = useState({ name: "", email: "" });

  const fetchProfile = async () => {
    const res = await axios.get("/profile", getAuthHeader());
    setProfile(res.data);
    setNewData({ name: res.data.name, email: res.data.email });
  };

  const saveProfile = async () => {
    await axios.put("/profile", newData, getAuthHeader());
    setEditing(false);
    fetchProfile();
  };

  useEffect(() => {
    fetchProfile();
  }, []);

  return (
    <div className="profile">
      <h2>Profile</h2>
      {editing ? (
        <>
          <input
            type="text"
            value={newData.name}
            onChange={e => setNewData({ ...newData, name: e.target.value })}
          />
          <input
            type="email"
            value={newData.email}
            onChange={e => setNewData({ ...newData, email: e.target.value })}
          />
          <button onClick={saveProfile}>Save</button>
        </>
      ) : (
        <>
          <p>Name: {profile.name}</p>
          <p>Email: {profile.email}</p>
          <button onClick={() => setEditing(true)}>Edit</button>
        </>
      )}
      <br />
      <Link to="/dashboard">⬅ Back</Link>
    </div>
  );
}

// ✅ Private Route
function PrivateRoute({ children }) {
  return localStorage.getItem("token") ? children : <Navigate to="/login" />;
}

// ✅ Main App
export default function App() {
  return (
    <Router>
      <Routes>
        <Route path="/" element={<Navigate to="/login" />} />
        <Route path="/login" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route
          path="/dashboard"
          element={<PrivateRoute><Dashboard /></PrivateRoute>}
        />
        <Route
          path="/profile"
          element={<PrivateRoute><Profile /></PrivateRoute>}
        />
      </Routes>
    </Router>
  );
}
